import axios from 'axios';

const url = 'https://covid19.mathdro.id/api';

export const fetchGlobalData = async (country) => {
	let changeableUrl = url;

	if (country) {
		changeableUrl = `${url}/countries/${country}`;
	}

	try {
		const { data: { confirmed, recovered, deaths, lastUpdate } } = await axios.get(changeableUrl);

		return { confirmed, recovered, deaths, lastUpdate };
	} catch (error) {
		console.log(error);
	}
}

export const fetchStateData = async (state) => {
	try {
		let { data: confirmed } = await axios.get(`${url}/countries/USA/confirmed`);
		let { data: deaths } = await axios.get(`${url}/countries/USA/deaths`);

		if (state !== '') {
			const stateConfirmedItems = confirmed.filter((item) => item.provinceState === state);
			const stateDeathItems = deaths.filter((item) => item.provinceState === state);

			if (stateConfirmedItems.length > 1) {
				confirmed = stateConfirmedItems
					.map((item) => item.confirmed)
					.reduce((total, currentValue) => total + currentValue);
			} else {
				confirmed = stateConfirmedItems.confirmed;
			}

			if (stateDeathItems.length > 1) {
				deaths = stateDeathItems
					.map((item) => item.deaths)
					.reduce((total, currentValue) => total + currentValue);
			} else {
				deaths = stateDeathItems.deaths;
			}
		} else {
			const stateConfirmedItems = confirmed.filter((item) => item.provinceState === state);
			const stateDeathItems = deaths.filter((item) => item.provinceState === state);

			confirmed = confirmed.value;
			deaths = deaths.value;
		}

		return { confirmed, deaths };
	} catch (error) {
		console.log(error);
	}
}

export const fetchDailyData = async () => {
	try {
		const { data } = await axios.get(`${url}/daily`);

		const modifiedData = data.map((dailyData) => ({
			confirmed: dailyData.confirmed.total,
			deaths: dailyData.deaths.total,
			date: dailyData.reportDate
		}));

		return modifiedData;
	} catch (error) {
		console.log(error);
	}
}

export const fetchCountries = async () => {
	try {
		const { data: { countries }} = await axios.get(`${url}/countries`);

		return countries.map((country) => country.name);
	} catch (error) {
		console.log(error);
	}
}

export const fetchStates = async () => {
	try {
		const usaConfirmed = await axios.get(`${url}/countries/USA/confirmed`);
		const usaDeaths = await axios.get(`${url}/countries/USA/deaths`);
		const usaConfirmedStates = usaConfirmed.data.map((entry) => entry.provinceState);
		const usaDeathStates = usaDeaths.data.map((entry) => entry.provinceState);

		return [...new Set([...usaConfirmedStates, ...usaDeathStates])].sort();
	} catch (error) {
		console.log(error);
	}
}
