import React from 'react';

import { Cards, WorldChart, USChart, CountryPicker, StatePicker } from './components';
import styles from './App.module.css';
import { fetchGlobalData, fetchStateData } from './api';

import CoronaImage from './images/image.png';

class App extends React.Component {
	state = {
		globalData: {},
		stateData: {},
		country: '',
		state: ''
	}

	async componentDidMount() {
		const fetchedGlobalData = await fetchGlobalData();
		const fetchedStateData = await fetchStateData();
		console.log(fetchedStateData);
		this.setState({ globalData: fetchedGlobalData, stateData: fetchedStateData });
	}

	handleCountryChange = async (country) => {
		const fetchedGlobalData = await fetchGlobalData(country);

		window.scrollTo(0, 0);

		this.setState({ globalData: fetchedGlobalData, country: country });
	}

	handleStateChange = async (state) => {
		const fetchedStateData = await fetchStateData(state);

		window.scrollTo(0, 0);

		this.setState({ stateData: fetchedStateData, state: state });
	}

	render() {
		const { globalData, stateData, country, state } = this.state;

		return (
			<div className={styles.container}>
				<img className={styles.image} src={CoronaImage} alt="COVID-19"/>
				<h1>{!country ? 'Global' : country}</h1>
				<Cards data={globalData}/>
				<CountryPicker handleCountryChange={this.handleCountryChange}/>
				<WorldChart data={globalData} country={country}/>
				<StatePicker handleStateChange={this.handleStateChange}/>
				<USChart data={stateData} state={state}/>
			</div>
		)
	}
}

export default App;
