import React from 'react';
import { Bar } from 'react-chartjs-2';

import styles from './USChart.module.css';

const USChart = ({ data: { confirmed, deaths }, state }) => {
	const barChart = (
		confirmed
			? (
				<Bar
					data={{
						labels: ['Infected', 'Deaths'],
						datasets: [{
							label: 'People',
							backgroundColor: [
								'rgba(0, 0, 255, 0.5)',
								'rgba(255, 0, 0, 0.5)'
							],
							data: [confirmed, deaths]
						}]
					}}
					options={{
						legend: { display: false },
						title: { display: true, text: (state === '') ? '' : `Current state in ${state}`}
					}}
				/>
			) : null
	);

	return (
		<div className={styles.container}>
			{barChart}
		</div>
	)
}

export default USChart;
